import{_ as e,c as o,o as t,V as a}from"./chunks/framework.j7JTtqwr.js";const x=JSON.parse('{"title":"Nginx","description":"","frontmatter":{},"headers":[],"relativePath":"Nginx.md","filePath":"Nginx.md","lastUpdated":1710670412000}'),c={name:"Nginx.md"},n=a('<h1 id="nginx" tabindex="-1">Nginx <a class="header-anchor" href="#nginx" aria-label="Permalink to &quot;Nginx&quot;">​</a></h1><p>Nginx安装完成后默认放到 <code>etc</code> 目录下</p><h2 id="背景介绍" tabindex="-1">背景介绍 <a class="header-anchor" href="#背景介绍" aria-label="Permalink to &quot;背景介绍&quot;">​</a></h2><p>Nginx是一个具有高性能的 <code>HTTP</code> 和 <code>反向代理</code> 的 WEB服务器，同时也是一个 <code>POP3/SMTP/IMAP代理服务器</code> ，是由 <code>伊戈尔・赛索耶夫</code>（俄罗斯人）使用 <code>C语言</code> 编写的，Nginx的第一个版本是2004年10月4号发布的 <code>0.1.0</code> 版本。另外值得一提的是 <code>伊戈尔・赛索耶夫</code> 将Nginx的源码进行了开源，这也为Nginx的发展提供了良好的保障。</p><h2 id="名词解释" tabindex="-1">名词解释 <a class="header-anchor" href="#名词解释" aria-label="Permalink to &quot;名词解释&quot;">​</a></h2><blockquote><p>WEB服务器</p></blockquote><p>WEB服务器也叫网页服务器，英文名叫 <code>Web Server</code>，主要功能是为用户提供网上信息浏览服务。</p><blockquote><p>HTTP</p></blockquote><p>HTTP是超文本传输协议的缩写，是用于从WEB服务器传输超文本到本地浏览器的传输协议，也是互联网上应用广泛的一种网络协议。HTTP是一个客户端和服务器端请求和应答的标准，客户端是终端用户，服务端是网站，通过使用Web浏览器、网络爬虫或者其他工具（Postman等），客户端发起一个到服务器上指定端口的HTTP请求。</p><blockquote><p>POP3/SMTP/IMAP</p></blockquote><p>POP3（Post Offic Protocol 3）：邮局协议的第三个版本。</p><p>SMTP（Simple Mail Transfer Protocol）：简单邮件传输协议。</p><p>IMAP（Internet Mail Access Protocol）：交互式邮件存取协议。</p><p>通过上面的名词解释，我们可以了解到Nginx也可以作为电子邮件代理服务器。</p><blockquote><p>反向代理</p></blockquote><p>正向代理：代理服务器接收客户端的请求并把客户端请求转发给服务端，服务端把数据交给代理服务器，代理服务器再把数据交还给客户端，然后客户端就可以看到服务端返回的数据。</p><p><strong>正向代理服务的是客户端</strong></p><p>反向代理：</p><p><strong>反向代理服务的是服务端</strong></p>',19),r=[n];function p(i,d,s,l,P,_){return t(),o("div",null,r)}const g=e(c,[["render",p]]);export{x as __pageData,g as default};
